  1→import { getFloorElevation } from '@/domain/floorModels';
  2→import { getSlabBottomLevel } from '@/elevations/slab';
  3→import { getBeamRenderData } from '@/geometry/beamGeometry';
  4→import { computeLandingElevation } from '@/geometry/landingGeometry';
  5→import { isValidSlabBoundary } from '@/geometry/slabGeometry';
  6→import { getStairRenderData } from '@/geometry/stairGeometry';
  7→import { wallDirection, wallLength, wallOutline } from '@/geometry/wallGeometry';
  8→import { buildWallPreviewContexts, buildWallSolidSegments } from './wallPreviewContext';
  9→
 10→const FIXTURE_3D_HEIGHTS = {
 11→  kitchenTop: 900,
 12→  toilet: 400,
 13→  lavatory: 850,
 14→  table: 750,
 15→  tv: 750,
 16→  sofa: 800,
 17→  bed: 550,
 18→};
 19→
 20→const DOOR_INSERT_THICKNESS_MIN = 35;
 21→const DOOR_INSERT_THICKNESS_MAX = 70;
 22→const WINDOW_INSERT_THICKNESS_MIN = 45;
 23→const WINDOW_INSERT_THICKNESS_MAX = 90;
 24→
 25→function createBoundsFromPoints(points, baseElevation, topElevation) {
 26→  if (!points?.length) {
 27→    return {
 28→      minX: 0,
 29→      maxX: 0,
 30→      minY: 0,
 31→      maxY: 0,
 32→      minElevation: baseElevation,
 33→      maxElevation: topElevation,
 34→    };
 35→  }
 36→
 37→  return {
 38→    minX: Math.min(...points.map((point) => point.x)),
 39→    maxX: Math.max(...points.map((point) => point.x)),
 40→    minY: Math.min(...points.map((point) => point.y)),
 41→    maxY: Math.max(...points.map((point) => point.y)),
 42→    minElevation: baseElevation,
 43→    maxElevation: topElevation,
 44→  };
 45→}
 46→
 47→function createPrismDescriptor(id, kind, outline, baseElevation, height, metadata = {}) {
 48→  const topElevation = baseElevation + height;
 49→  return {
 50→    id,
 51→    kind,
 52→    geometry: 'prism',
 53→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
 54→    baseElevation,
 55→    height,
 56→    materialKey: metadata.materialKey || kind,
 57→    metadata,
 58→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 59→  };
 60→}
 61→
 62→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 63→  const outline = wallOutline({
 64→    start: { x: startPoint.x, y: startPoint.y },
 65→    end: { x: endPoint.x, y: endPoint.y },
 66→    thickness: width,
 67→  });
 68→  const direction = wallDirection({
 69→    start: { x: startPoint.x, y: startPoint.y },
 70→    end: { x: endPoint.x, y: endPoint.y },
 71→  });
 72→  const topElevation = baseElevation + height;
 73→
 74→  return {
 75→    id,
 76→    kind,
 77→    geometry: 'box',
 78→    center: {
 79→      x: (startPoint.x + endPoint.x) / 2,
 80→      y: (startPoint.y + endPoint.y) / 2,
 81→    },
 82→    size: {
 83→      x: wallLength({ start: startPoint, end: endPoint }),
 84→      y: height,
 85→      z: width,
 86→    },
 87→    rotation: Math.atan2(direction.y, direction.x),
 88→    baseElevation,
 89→    materialKey: metadata.materialKey || kind,
 90→    metadata,
 91→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 92→  };
 93→}
 94→
 95→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 96→  const halfX = size.x / 2;
 97→  const halfZ = size.z / 2;
 98→  const cos = Math.cos(rotation);
 99→  const sin = Math.sin(rotation);
100→  const corners = [
101→    { x: -halfX, y: -halfZ },
102→    { x: halfX, y: -halfZ },
103→    { x: halfX, y: halfZ },
104→    { x: -halfX, y: halfZ },
105→  ].map((point) => ({
106→    x: center.x + (point.x * cos - point.y * sin),
107→    y: center.y + (point.x * sin + point.y * cos),
108→  }));
109→
110→  return {
111→    id,
112→    kind,
113→    geometry: 'box',
114→    center: { x: center.x, y: center.y },
115→    size,
116→    rotation,
117→    baseElevation,
118→    materialKey: metadata.materialKey || kind,
119→    metadata,
120→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
121→  };
122→}
123→
124→function resolveLandingElevation(landing, stairs, floorLevel) {
125→  if (landing.elevation) return landing.elevation;
126→  return computeLandingElevation(landing, stairs, floorLevel) - floorLevel;
127→}
128→
129→function createStairDescriptor(stair, floorLevel, floorId, landings, landingElevationMap) {
130→  const renderData = getStairRenderData(stair);
131→  if (!renderData?.outline?.length) return null;
132→
133→  let baseElevation = floorLevel;
134→  if (stair.startLandingAttachment) {
135→    const elev = landingElevationMap?.get(stair.startLandingAttachment.landingId);
136→    if (elev != null) {
137→      baseElevation = floorLevel + elev;
138→    }
139→  }
140→
141→  return {
142→    id: stair.id,
143→    kind: 'stair',
144→    geometry: 'stair',
145→    startPoint: { ...stair.startPoint },
146→    width: stair.width,
147→    numberOfRisers: stair.numberOfRisers,
148→    riserHeight: stair.riserHeight,
149→    treadDepth: stair.treadDepth,
150→    angle: renderData.angle,
151→    baseElevation,
152→    materialKey: 'stair',
153→    metadata: {
154→      sourceId: stair.id,
155→      floorId,
156→    },
157→    bounds: createBoundsFromPoints(
158→      renderData.outline,
159→      baseElevation,
160→      baseElevation + renderData.totalRise
161→    ),
162→  };
163→}
164→
165→function buildWallObjects(wallContexts) {
166→  return wallContexts.flatMap((context) => (
167→    buildWallSolidSegments(context).map((segment) => createLinearBoxDescriptor(
168→      segment.id,
169→      'wall',
170→      segment.startPoint,
171→      segment.endPoint,
172→      segment.thickness,
173→      segment.baseElevation,
174→      segment.topElevation - segment.baseElevation,
175→      {
176→        sourceId: segment.wallId,
177→        floorId: segment.floorId,
178→        wallId: segment.wallId,
179→      }
180→    ))
181→  ));
182→}
183→
184→function buildSlabObjects(floor) {
185→  return (floor.slabs || [])
186→    .filter(slab => isValidSlabBoundary(slab.boundaryPoints))
187→    .map(slab => createPrismDescriptor(
188→      slab.id,
189→      'slab',
190→      slab.boundaryPoints,
191→      getSlabBottomLevel(slab),
192→      slab.thickness ?? 0,
193→      {
194→        sourceId: slab.id,
195→        floorId: floor.id,
196→      }
197→    ));
198→}
199→
200→function buildColumnObjects(floor, floorLevel) {
201→  return (floor.columns || []).map((column) => createBoxDescriptor(
202→    column.id,
203→    'column',
204→    { x: column.x, y: column.y },
205→    {
206→      x: column.width,
207→      y: column.height,
208→      z: column.depth,
209→    },
210→    floorLevel,
211→    (column.rotation || 0) * Math.PI / 180,
212→    {
213→      sourceId: column.id,
214→      floorId: floor.id,
215→    }
216→  ));
217→}
218→
219→function buildBeamObjects(floor) {
220→  return (floor.beams || [])
221→    .map((beam) => {
222→      const renderData = getBeamRenderData(beam, floor.columns || []);
223→      if (!renderData) return null;
224→
225→      return createLinearBoxDescriptor(
226→        beam.id,
227→        'beam',
228→        renderData.start,
229→        renderData.end,
230→        beam.width,
231→        beam.floorLevel - beam.depth,
232→        beam.depth,
233→        {
234→          sourceId: beam.id,
235→          floorId: floor.id,
236→        }
237→      );
238→    })
239→    .filter(Boolean);
240→}
241→
242→function getInsertThickness(kind, wallThickness) {
243→  if (kind === 'door') {
244→    return Math.max(
245→      DOOR_INSERT_THICKNESS_MIN,
246→      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)
247→    );
248→  }
249→
250→  return Math.max(
251→    WINDOW_INSERT_THICKNESS_MIN,
252→    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)
253→  );
254→}
255→
256→function createOpeningInsertDescriptor(opening) {
257→  return createBoxDescriptor(
258→    opening.id,
259→    opening.kind,
260→    opening.centerPoint,
261→    {
262→      x: opening.visibleWidth,
263→      y: opening.visibleHeight,
264→      z: getInsertThickness(opening.kind, opening.wallThickness),
265→    },
266→    opening.visibleBaseElevation,
267→    opening.angle,
268→    {
269→      sourceId: opening.sourceId,
270→      floorId: opening.metadata.floorId,
271→      wallId: opening.wallId,
272→      openingKind: opening.kind,
273→    }
274→  );
275→}
276→
277→function buildDoorObjects(wallContexts) {
278→  return wallContexts
279→    .flatMap((context) => context.openings)
280→    .filter((opening) => opening.kind === 'door')
281→    .map((opening) => createOpeningInsertDescriptor(opening));
282→}
283→
284→function buildWindowObjects(wallContexts) {
285→  return wallContexts
286→    .flatMap((context) => context.openings)
287→    .filter((opening) => opening.kind === 'window')
288→    .map((opening) => {
289→      const desc = createOpeningInsertDescriptor(opening);
290→      desc.geometry = 'window';
291→      desc.windowType = opening.type || 'standard';
292→      desc.openDirection = opening.openDirection || 'left';
293→      return desc;
294→    });
295→}
296→
297→function buildStairObjects(floor, floorLevel, landings, landingElevationMap) {
298→  return (floor.stairs || [])
299→    .map((stair) => createStairDescriptor(stair, floorLevel, floor.id, landings, landingElevationMap))
300→    .filter(Boolean);
301→}
302→
303→function buildLandingObjects(floor, floorLevel, landingElevationMap) {
304→  return (floor.landings || []).map((landing) => createBoxDescriptor(
305→    landing.id,
306→    'landing',
307→    { x: landing.position.x, y: landing.position.y },
308→    {
309→      x: landing.width,
310→      y: landing.thickness ?? 200,
311→      z: landing.depth,
312→    },
313→    floorLevel + (landingElevationMap.get(landing.id) || 0),
314→    (landing.rotation || 0) * Math.PI / 180,
315→    {
316→      sourceId: landing.id,
317→      floorId: floor.id,
318→    }
319→  ));
320→}
321→
322→function buildFixtureObjects(floor, floorLevel) {
323→  return (floor.fixtures || []).map((fixture) => {
324→    const descriptor = createBoxDescriptor(
325→      fixture.id,
326→      'fixture',
327→      { x: fixture.x, y: fixture.y },
328→      {
329→        x: fixture.width,
330→        y: FIXTURE_3D_HEIGHTS[fixture.fixtureType] || 750,
331→        z: fixture.depth,
332→      },
333→      floorLevel,
334→      (fixture.rotation || 0) * Math.PI / 180,
335→      {
336→        sourceId: fixture.id,
337→        floorId: floor.id,
338→        materialKey: 'fixture_' + fixture.fixtureType,
339→      }
340→    );
341→    descriptor.geometry = 'fixture';
342→    descriptor.fixtureType = fixture.fixtureType;
343→    return descriptor;
344→  });
345→}
346→
347→export function buildFloorPreviewObjects(floor) {
348→  const floorLevel = getFloorElevation(floor);
349→  const landings = floor.landings || [];
350→  const stairs = floor.stairs || [];
351→
352→  const landingElevationMap = new Map(
353→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorLevel)])
354→  );
355→
356→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
357→
358→  return [
359→    ...buildSlabObjects(floor),
360→    ...buildWallObjects(wallContexts),
361→    ...buildColumnObjects(floor, floorLevel),
362→    ...buildBeamObjects(floor),
363→    ...buildStairObjects(floor, floorLevel, landings, landingElevationMap),
364→    ...buildLandingObjects(floor, floorLevel, landingElevationMap),
365→    ...buildDoorObjects(wallContexts),
366→    ...buildWindowObjects(wallContexts),
367→    ...buildFixtureObjects(floor, floorLevel),
368→  ];
369→}
