  1→import { generateId } from './ids';
  2→import { WALL_THICKNESS, WALL_HEIGHT, DOOR_WIDTH, DOOR_HEIGHT, DOOR_SILL_HEIGHT, WINDOW_WIDTH, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT, COLUMN_WIDTH, COLUMN_DEPTH, BEAM_WIDTH, BEAM_DEPTH, STAIR_WIDTH, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, SLAB_THICKNESS, SLAB_ELEVATION, SECTION_DEPTH, LANDING_WIDTH, LANDING_DEPTH, LANDING_THICKNESS, ROOM_COLOR, DIMENSION_DEFAULT_OFFSET } from './defaults';
  3→import { FIXTURE_DEFAULTS } from '@/editor/tools';
  4→import { polygonArea, polygonCentroid } from '@/geometry/polygon';
  5→
  6→export function createProject(name = 'Untitled Project') {
  7→  return {
  8→    id: generateId('proj'),
  9→    name,
 10→    createdAt: new Date().toISOString(),
 11→    updatedAt: new Date().toISOString(),
 12→    floors: [createFloor('Ground Floor', 0, { elevation: 0, floorToFloorHeight: WALL_HEIGHT })],
 13→    sheets: [],
 14→    version: 1,
 15→  };
 16→}
 17→
 18→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 19→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 20→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 21→
 22→  return {
 23→    id: generateId('floor'),
 24→    name,
 25→    levelIndex,
 26→    elevation,
 27→    floorToFloorHeight,
 28→    walls: [],
 29→    rooms: [],
 30→    doors: [],
 31→    windows: [],
 32→    columns: [],
 33→    beams: [],
 34→    stairs: [],
 35→    landings: [],
 36→    fixtures: [],
 37→    annotations: [],
 38→    annotationSettings: createAnnotationSettings(),
 39→    slabs: [],
 40→    sectionCuts: [],
 41→  };
 42→}
 43→
 44→export function nextSectionLabel(existingCuts = []) {
 45→  const usedLetters = new Set(
 46→    existingCuts
 47→      .map(c => {
 48→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 49→        return match ? match[1] : null;
 50→      })
 51→      .filter(Boolean)
 52→  );
 53→  for (let i = 0; i < 26; i++) {
 54→    const letter = String.fromCharCode(65 + i);
 55→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 56→  }
 57→  return `Section ${existingCuts.length + 1}`;
 58→}
 59→
 60→export function createAnnotationSettings(overrides = {}) {
 61→  return {
 62→    showWallDimensions: overrides.showWallDimensions ?? true,
 63→    showRoomDimensions: overrides.showRoomDimensions ?? true,
 64→    showOverallDimensions: overrides.showOverallDimensions ?? true,
 65→    showObjectTags: overrides.showObjectTags ?? true,
 66→    showElevationOverallDimensions: overrides.showElevationOverallDimensions ?? true,
 67→    showElevationLevelDimensions: overrides.showElevationLevelDimensions ?? true,
 68→    showElevationOpeningDimensions: overrides.showElevationOpeningDimensions ?? true,
 69→  };
 70→}
 71→
 72→export function createLinearDimensionAnnotation(startPoint, endPoint, options = {}) {
 73→  return {
 74→    id: generateId('anno'),
 75→    type: 'dimension',
 76→    mode: options.mode ?? 'aligned',
 77→    startPoint: { x: startPoint.x, y: startPoint.y },
 78→    endPoint: { x: endPoint.x, y: endPoint.y },
 79→    offset: options.offset ?? DIMENSION_DEFAULT_OFFSET,
 80→    textOverride: options.textOverride ?? '',
 81→  };
 82→}
 83→
 84→export function createWall(start, end, thickness = WALL_THICKNESS, options = {}) {
 85→  return {
 86→    id: generateId('wall'),
 87→    start: { x: start.x, y: start.y },
 88→    end: { x: end.x, y: end.y },
 89→    thickness,
 90→    height: options.height ?? WALL_HEIGHT,
 91→    startAttachment: options.startAttachment ?? null,
 92→    endAttachment: options.endAttachment ?? null,
 93→  };
 94→}
 95→
 96→export function createDoor(wallId, offset, width = DOOR_WIDTH, openDirection = 'left', type = 'swing') {
 97→  return {
 98→    id: generateId('door'),
 99→    wallId,
100→    offset,
101→    width,
102→    height: DOOR_HEIGHT,
103→    sillHeight: DOOR_SILL_HEIGHT,
104→    openDirection,
105→    type,
106→  };
107→}
108→
109→export function createWindow(wallId, offset, width = WINDOW_WIDTH, type = 'standard', openDirection = 'left') {
110→  return {
111→    id: generateId('win'),
112→    wallId,
113→    offset,
114→    width,
115→    height: WINDOW_HEIGHT,
116→    sillHeight: WINDOW_SILL_HEIGHT,
117→    type,
118→    openDirection,
119→  };
120→}
121→
122→export function createColumn(x, y, width = COLUMN_WIDTH, depth = COLUMN_DEPTH, options = {}) {
123→  return {
124→    id: generateId('col'),
125→    x, y, width, depth,
126→    height: options.height ?? 3000,
127→    rotation: options.rotation ?? 0,
128→    type: options.type ?? 'rectangular',
129→    name: options.name ?? '',
130→    showLabel: options.showLabel ?? false,
131→  };
132→}
133→
134→export function createBeam(startRef, endRef, width = BEAM_WIDTH, depth = BEAM_DEPTH, floorLevel = 0) {
135→  return {
136→    id: generateId('beam'),
137→    startRef: { ...startRef },
138→    endRef: { ...endRef },
139→    width,
140→    depth,
141→    floorLevel,
142→  };
143→}
144→
145→export function createSlab(floorId, boundaryPoints = [], thickness = SLAB_THICKNESS, elevation = SLAB_ELEVATION, options = {}) {
146→  return {
147→    id: generateId('slab'),
148→    floorId,
149→    boundaryPoints: boundaryPoints.map(point => ({ x: point.x, y: point.y })),
150→    thickness,
151→    elevation,
152→    name: options.name ?? '',
153→    type: options.type ?? '',
154→  };
155→}
156→
157→export function createStair(startPoint, width = STAIR_WIDTH, numberOfRisers = STAIR_RISERS, riserHeight = STAIR_RISER_HEIGHT, treadDepth = STAIR_TREAD_DEPTH, direction = { angle: 0 }, floorRelation = {}, options = {}) {
158→  return {
159→    id: generateId('stair'),
160→    startPoint: { x: startPoint.x, y: startPoint.y },
161→    width,
162→    numberOfRisers,
163→    riserHeight,
164→    treadDepth,
165→    direction: {
166→      angle: direction?.angle ?? 0,
167→    },
168→    floorRelation: {
169→      fromFloorId: floorRelation.fromFloorId ?? null,
170→      toFloorId: floorRelation.toFloorId ?? null,
171→    },
172→    startLandingAttachment: options.startLandingAttachment ?? null,
173→    endLandingAttachment: options.endLandingAttachment ?? null,
174→  };
175→}
176→
177→export function createLanding(position, width = LANDING_WIDTH, depth = LANDING_DEPTH, options = {}) {
178→  return {
179→    id: generateId('landing'),
180→    position: { x: position.x, y: position.y },
181→    width,
182→    depth,
183→    thickness: options.thickness ?? LANDING_THICKNESS,
184→    elevation: options.elevation ?? 0,
185→    rotation: options.rotation ?? 0,
186→  };
187→}
188→
189→export function createFixture(fixtureType, x, y, options = {}) {
190→  const defaults = FIXTURE_DEFAULTS[fixtureType] || { width: 600, depth: 400 };
191→  return {
192→    id: generateId('fix'),
193→    fixtureType,
194→    x, y,
195→    width: options.width ?? defaults.width,
196→    depth: options.depth ?? defaults.depth,
197→    rotation: options.rotation ?? 0,
198→    name: options.name ?? '',
199→  };
200→}
201→
202→export function createSectionCut(startPoint, endPoint, options = {}) {
203→  return {
204→    id: generateId('section'),
205→    startPoint: { x: startPoint.x, y: startPoint.y },
206→    endPoint: { x: endPoint.x, y: endPoint.y },
207→    depth: options.depth ?? SECTION_DEPTH,
208→    label: options.label ?? 'Section A-A',
209→    direction: options.direction ?? 1,
210→  };
211→}
212→
213→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
214→  const area = polygonArea(points);
215→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
216→  return {
217→    id: generateId('room'),
218→    name,
219→    points: points.map(p => ({ x: p.x, y: p.y })),
220→    labelPosition: { ...centroid },
221→    color,
222→    area,
223→  };
224→}
