 1→import { isValidSlabBoundary } from '@/geometry/slabGeometry';
 2→import { projectElevationDepth, projectElevationHorizontal } from './projection';
 3→
 4→const EPSILON = 1e-6;
 5→
 6→function getBoundaryEdges(points = []) {
 7→  if (points.length < 2) return [];
 8→
 9→  return points.map((point, index) => ({
10→    start: point,
11→    end: points[(index + 1) % points.length],
12→    index,
13→  }));
14→}
15→
16→function projectEdge(view, edge) {
17→  const startHorizontal = projectElevationHorizontal(view, edge.start);
18→  const endHorizontal = projectElevationHorizontal(view, edge.end);
19→  const left = Math.min(startHorizontal, endHorizontal);
20→  const right = Math.max(startHorizontal, endHorizontal);
21→
22→  if (Math.abs(right - left) < EPSILON) return null;
23→
24→  return {
25→    left,
26→    right,
27→    depth: (
28→      projectElevationDepth(view, edge.start) +
29→      projectElevationDepth(view, edge.end)
30→    ) / 2,
31→    edgeIndex: edge.index,
32→  };
33→}
34→
35→export function getSlabTopLevel(slab) {
36→  return slab?.elevation ?? 0;
37→}
38→
39→export function getSlabBottomLevel(slab) {
40→  return getSlabTopLevel(slab) - (slab?.thickness ?? 0);
41→}
42→
43→export function buildSlabElevationBands(slab, view) {
44→  if (!slab || !isValidSlabBoundary(slab.boundaryPoints)) return [];
45→
46→  return getBoundaryEdges(slab.boundaryPoints)
47→    .map((edge) => projectEdge(view, edge))
48→    .filter(Boolean);
49→}
